#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int n, k;
int dist[MAXN][MAXN];
int a, b;
int main() {
    scanf("%d", &n);
    for (int i = 1; i < n; i++) {
        scanf("%d %d", &a, &b);
        dist[a][b] = dist[b][a] = 1;
    }
    for (int k = 1; k < n; k++) {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (dist[i][k] && dist[k][j]) {
                    if (!dist[i][j] || dist[i][j] > dist[i][k] + dist[k][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }
    }
    scanf("%d", &k);
    for (int i = 0; i < k; i++) {
        scanf("%d %d", &a, &b);
        printf("%d\n", dist[a][b]);
    }
    return 0;
}

