const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
const MAXN = 100005;
let dist = new Array(MAXN).fill(0).map(() => new Array(MAXN).fill(0));
let input = [];
rl.on('line', line => {
    input.push(line);
}).on('close', () => {
    let n = parseInt(input.shift());
    for (let i = 1; i < n; i++) {
        let [a, b] = input.shift().split(' ').map(x => parseInt(x));
        dist[a][b] = dist[b][a] = 1;
    }
    for (let k = 1; k < n; k++) {
        for (let i = 1; i <= n; i++) {
            for (let j = 1; j <= n; j++) {
                if (dist[i][k] && dist[k][j]) {
                    if (!dist[i][j] || dist[i][j] > dist[i][k] + dist[k][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }
    }
    let k = parseInt(input.shift());
    for (let i = 0; i < k; i++) {
        let [a, b] = input.shift().split(' ').map(x => parseInt(x));
        console.log(dist[a][b]);
    }
});

